// Valida payload del CRM y prepara el cuerpo para Evolution API
const body = $input.first().json.body || {};

const contactId = String(body.contactId || '').trim();
const rawPhone = String(body.phone || '').trim();
const phone = rawPhone.replace(/\D/g, '');
const mediaUrl = String(body.mediaUrl || '').trim();
const mediaType = String(body.mediaType || 'file').trim().toLowerCase();
const fileName = String(body.fileName || 'archivo').trim().replace(/[^A-Za-z0-9._-]/g, '_').slice(0, 200);
const mimeType = String(body.mimeType || 'application/octet-stream').trim().slice(0, 120);
const caption = String(body.caption || '').trim().slice(0, 1024);
const userName = String(body.userName || 'Administrador CRM').trim().slice(0, 120);

const validId = /^[A-Za-z0-9_-]{1,128}$/.test(contactId);
const validPhone = /^\d{8,20}$/.test(phone);
const validUrl = /^https?:\/\/.+/i.test(mediaUrl);
const allowedTypes = ['image', 'video', 'audio', 'file'];

if (!validId || !validPhone || !validUrl || !allowedTypes.includes(mediaType)) {
  return [{ json: { ok: false, status: 400, error: 'Payload inválido', detalle: { validId, validPhone, validUrl, mediaType } } }];
}

const evolutionMediaType = mediaType === 'file' ? 'document' : mediaType;

return [{ json: {
  ok: true,
  contactId,
  phone,
  mediaUrl,
  mediaType,
  evolutionMediaType,
  fileName,
  mimeType,
  caption,
  userName
} }];
